head.script:
	/**
	 * 화면 초기화
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// [전체공통] 화면초기화 공통 함수 호출
		dmaReqInfo.set("usrId",$p.getParameter( "empNo" ));

		dmaReqInfo.set("biznDivCd","PG");
		dmaReqInfo.set("sysDivCd","ECS");
		scwin.login();
		 //dmaReqInfo.set($p.getParameter( "empNo" ) );
 		//alert($p.getParameter( "empNo" ) );
		// 공통 코드 설정
	};


	/**
	 * 로그인 버튼 클릭 함수
	 * @param
	 * @return
	 */
	scwin.btnLogin_onclick = function() {
		scwin.login();
	};

	/**
	 * 로그인 처리 함수
	 * @param
	 * @return
	 */
	scwin.login = function() {
		var usrId = dmaReqInfo.get("usrId");
		if (usrId == "") {
			// comLib.alert($p, "잘못된 접근입니다.");
			if (parent && parent != this) {
				parent.location.href = window.location.protocol + "//" + window.location.host + "/sessionnull.html";
			} else {
				window.location.href=window.location.protocol +"//"+window.location.host + "/sessionnull.html";
			}
			return false;
		} else {
			var requestData = {
				"dmaReqInfo" : dmaReqInfo.getJSON()
			};
			var option = {
				action : "/zz/login/loginIntnUsr.do",
				reqData : requestData,
				resData : dmaLoginUsrInfo,
				success : "scwin.loginCallback",
				isShowMeg : false
			};
			ajaxLib.executeAjax($p, option);
		}
	};

	/**
	 * 로그인 처리 콜백 함수
	 * @param resBody:서비스단에서 받은 데이터
	 * @return
	 */
	scwin.loginCallback = function(resBody) {
		if ( resBody.message.code === comLib.STATUS_SUCCESS ) {
			// if (cbxIsSaved.getValue() == "Y") {
				// comLib.setCookie("usrId", resBody.data.usrId, 31);
			// }

			//comLib.setGlobal("globalUserInfo", dmaLoginUsrInfo.getJSON());

			comLib.setUserInfo("usrId", 			dmaLoginUsrInfo.get("usrId"));
			comLib.setUserInfo("usrEmpno", 		dmaLoginUsrInfo.get("usrEmpno"));
			comLib.setUserInfo("usrNm", 		dmaLoginUsrInfo.get("usrNm"));
			comLib.setUserInfo("sysDivCd", 		dmaLoginUsrInfo.get("sysDivCd"));
			comLib.setUserInfo("biznDivCd", 	dmaLoginUsrInfo.get("biznDivCd"));
			comLib.setUserInfo("athrId", 		dmaLoginUsrInfo.get("athrId"));
			comLib.setUserInfo("usrDeptCd", 	dmaLoginUsrInfo.get("usrDeptCd"));
			comLib.setUserInfo("usrDeptNm", 	dmaLoginUsrInfo.get("usrDeptNm"));
			comLib.setUserInfo("usrOfcpsCd", 	dmaLoginUsrInfo.get("usrOfcpsCd"));
			comLib.setUserInfo("usrOfcpsNm", 	dmaLoginUsrInfo.get("usrOfcpsNm"));
			comLib.setUserInfo("usrJgrdCd", 	dmaLoginUsrInfo.get("usrJgrdCd"));
			comLib.setUserInfo("usrJgrdNm", 	dmaLoginUsrInfo.get("usrJgrdNm"));

			comLib.setUserInfo("usrHqCd", 		dmaLoginUsrInfo.get("usrHqCd"));
			comLib.setUserInfo("usrHqNm", 		dmaLoginUsrInfo.get("usrHqNm"));
			comLib.setUserInfo("usrSectCd", 	dmaLoginUsrInfo.get("usrSectCd"));
			comLib.setUserInfo("usrSectNm", 	dmaLoginUsrInfo.get("usrSectNm"));
			comLib.setUserInfo("usrTeamCd", 	dmaLoginUsrInfo.get("usrTeamCd"));
			comLib.setUserInfo("usrTeamNm", 	dmaLoginUsrInfo.get("usrTeamNm"));
			comLib.setUserInfo("usrJbgpCd", 	dmaLoginUsrInfo.get("usrJbgpCd"));
			comLib.setUserInfo("usrJbgpNm", 	dmaLoginUsrInfo.get("usrJbgpNm"));
			comLib.setUserInfo("usrJblnCd", 	dmaLoginUsrInfo.get("usrJblnCd"));
			comLib.setUserInfo("usrJblnNm", 	dmaLoginUsrInfo.get("usrJblnNm"));
			comLib.setUserInfo("usrDtyCd", 		dmaLoginUsrInfo.get("usrDtyCd"));
			comLib.setUserInfo("usrDtyNm", 		dmaLoginUsrInfo.get("usrDtyNm"));
			comLib.setUserInfo("cstctCd", 			dmaLoginUsrInfo.get("cstctCd"));

			comLib.setUserInfo("conectIp", 		dmaLoginUsrInfo.get("conectIp"));

			$w.url("/ui/index.xml", {
				"spa" : true,
				"replaceHistory" : true,
				"forceReload" : false
			});
		} else if (resBody.message.code === comLib.STATUS_DUP_LOGIN) {
			comLib.alert($p, resBody.message.code_name);
			scwin.login();
		} else {
			comLib.alert($p, resBody.message.code_name);
			// ibxUserId.focus();
		}
	};

	/**
	 * 화면 초기화 함수 처리
	 * @param
	 * @return
	 */
	 /*삭제
		if (scwin.initStatus) {
			scwin.initScreen();
		}
	*/
